SELECT s.*
FROM TB_SETTLEMENT s


        AND s.settle_date = #{settleDate}


        AND s.op_type = #{opType}


ORDER BY s.settle_date DESC, s.op_type ASC

SELECT COUNT(1) FROM TB_SETTLEMENT s


        AND s.settle_date = #{settleDate}


        AND s.op_type = #{opType}

SELECT IFNULL(SUM(total_pay_amt), 0) AS sum_pay_amt, IFNULL(SUM(order_count), 0) AS sum_order_cnt, IFNULL(SUM(total_vat_amt), 0) AS sum_vat_amt, IFNULL(ROUND(AVG(raw_material_ratio), 2), 0) AS avg_raw_ratio FROM TB_SETTLEMENT s
AND s.settle_date = #{settleDate}
AND s.op_type = #{opType}
